#include <stdio.h>
#include <stdlib.h>

int cmp_ll(const void *a, const void *b) {
    long long la = *(const long long *)a;
    long long lb = *(const long long *)b;
    if (la < lb) return -1;
    if (la > lb) return 1;
    return 0;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *arr = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &arr[i]);
        int total = N * (N + 1) / 2;
        long long *sums = (long long*)malloc(total * sizeof(long long));
        int cnt = 0;
        for (int i = 0; i < N; ++i) {
            long long cur = 0;
            for (int j = i; j < N; ++j) {
                cur += arr[j];
                sums[cnt++] = cur;
            }
        }
        qsort(sums, cnt, sizeof(long long), cmp_ll);
        int distinct = (cnt > 0) ? 1 : 0;
        for (int i = 1; i < cnt; ++i) if (sums[i] != sums[i-1]) ++distinct;
        printf("%d\n", distinct);
        free(arr);
        free(sums);
    }
    return 0;
}

